#include<bits/stdc++.h>
using namespace std;
int m,s,c,a[500005],b[500005],ans;
bool cmp(int x,int y){return x>y;}
int main(void){
	cin>>m>>s>>c;
	for(int i=1;i<=c;i++)cin>>a[i];
	sort(a+1,a+c+1);
	for(int i=1;i<=c-1;i++)b[i]=a[i+1]-a[i]-1;
	sort(b+1,b+c,cmp);
	ans=a[c]-a[1]+1;
	for(int i=1;i<=m-1;i++)ans-=b[i];
	cout<<ans;
    return false;
}
